var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"여어, <color=#ffd34c>황무지의 여우</color>. 오랜만이네.","JPN":"よお、<color=#ffd34c>荒れ地の狐</color>。久しぶりやな。","ENG":"Howdy, <color=#ffd34c>Wasteland Fox</color>. Haven’t seen ya in a while.","TWN":"喂，<color=#ffd34c>荒野狐狸</color>，好久不見。"},"stage":{"bg":"AIRDOME","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MILITARY_NPC_GMAECIRCLE_A","text":{"KOREA":"그러는 너는…… 세 가지 속성을 다루는 <color=#ffd34c>미리네★스타라이트</color>인가?","JPN":"お前は……三つの属性を操る<color=#ffd34c>マリ★スターライト</color>か？","ENG":"Y-you’re... <color=#ffd34c>Mi Rinae★Starlight</color>, the wielder of the three elements!","TWN":"你是……可以操控三種屬性的<color=#ffd34c>宓璃奈★星光</color>？"},"stage":{"bg":"AIRDOME","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MILITARY_NPC_GMAECIRCLE_A","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"뭔데, 그게!?","JPN":"何だよ、それ！？","ENG":"What’s that supposed to mean?","TWN":"什麼鬼？完全沒聽過啊！？"},"stage":{"bg":"AIRDOME","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"MILITARY_NPC_GMAECIRCLE_A","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"후후, 섣부르게 움직이지 않는 편이 좋을낀데?","JPN":"ふふ、うかつに動かんほうがええと思うで？","ENG":"Heh, I reckon ya better stay right where ya are...","TWN":"呵呵，勸你還是不要輕舉妄動唄？"},"stage":{"bg":"AIRDOME","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"MILITARY_NPC_GMAECIRCLE_A","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"아무리 황무지의 여우라캐도 불 속성 참격의 도트 데미지…… 그거 쪼매 아플끼다.","JPN":"いくら荒れ地の狐や言うても、炎属性斬撃のドットダメージ……ちょっと痛いからな。","ENG":"Not even Wasteland Fox can handle damage-over-time pyro damage... I reckon your wound feels hotter than a burnin’ stump.","TWN":"就算是荒野狐狸，遇到火屬性斬擊的連續傷害……也是會有點痛的。"},"stage":{"bg":"AIRDOME","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"MILITARY_NPC_GMAECIRCLE_A","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"평범하게 빗자루로 때려 놓고 무슨 불속성이냐고!","JPN":"普通にほうきで殴っておいて何が炎属性だよ！","ENG":"You just hit him with a broom! What pyro damage?!","TWN":"不就是拿一根掃把打人，哪來的火屬性啦！"},"stage":{"bg":"AIRDOME","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"MILITARY_NPC_GMAECIRCLE_A","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MILITARY_NPC_GMAECIRCLE_A","text":{"KOREA":"큭, 확실히 베인 곳이 화끈화끈하군. 썩 나쁘지 않은 참격이었어.","JPN":"くっ、確かに斬られたところがヒリヒリする。なかなか悪くない斬撃だった。","ENG":"Kggh, it really does feel like my wounds are burning. Not bad, Starlight.","TWN":"唔，被砍到的地方確實有點熱熱的，斬得漂亮！"},"stage":{"bg":"AIRDOME","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"MILITARY_NPC_GMAECIRCLE_A","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_NULL","text":{"KOREA":"아니, 그러니까 그런 거 일일이 받아주지 마!","JPN":"いや、だからそんなのにいちいち反応するなよ！","ENG":"Don’t play along with her absurdity!","TWN":"喂，你還接得下去喔！？"},"stage":{"bg":"AIRDOME","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BOX_NPC_GAMECIRCLE_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"MILITARY_NPC_GMAECIRCLE_A","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MILITARY_NPC_GMAECIRCLE_B","text":{"KOREA":"어라, 불속성? 무슨 소리야? 방금 평범하게 빗자루를…….","JPN":"あれ、炎属性？　どういうことだ？　今普通にほうきを……","ENG":"Huh? Fire element? But it was just an ordinary broom...","TWN":"什麼火屬性？在說什麼？不就是一根平凡的掃把……"},"stage":{"bg":"AIRDOME","slots":{"L":{"char_id":"MILITARY_NPC_GMAECIRCLE_B","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MILITARY_NPC_GMAECIRCLE_A","text":{"KOREA":"너, 이 자식! 지금 코미페의 금기를 어길 셈이냐?","JPN":"お前！　コミフェの禁忌を破るつもりなのか？","ENG":"You, you prick! You dare break the sacred rule of Comic Festival?","TWN":"臭小子！你現在是打算觸犯動漫展的禁忌嗎？"},"stage":{"bg":"AIRDOME","slots":{"L":{"char_id":"MILITARY_NPC_GMAECIRCLE_B","face":"UNIT_IDLE"},"C":{"char_id":"MILITARY_NPC_GMAECIRCLE_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MILITARY_NPC_GMAECIRCLE_B","text":{"KOREA":"그, 금기요?","JPN":"き、禁忌ですか？","ENG":"S-sacred rule?!","TWN":"什…什麼禁忌？"},"stage":{"bg":"AIRDOME","slots":{"L":{"char_id":"MILITARY_NPC_GMAECIRCLE_B","face":"UNIT_IDLE"},"C":{"char_id":"MILITARY_NPC_GMAECIRCLE_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MILITARY_NPC_GMAECIRCLE_A","text":{"KOREA":"그래! 여기서는 다른 사람의 설정에 트집을 잡으면 안 된다고 했잖아!","JPN":"そうだ！　ここでは他人の設定に口を出したらダメだって言っただろ！","ENG":"Yes, rule! You’re not supposed to doubt other people’s characters!","TWN":"我不是說過！不能戳破別人的人設！"},"stage":{"bg":"AIRDOME","slots":{"L":{"char_id":"MILITARY_NPC_GMAECIRCLE_B","face":"UNIT_IDLE"},"C":{"char_id":"MILITARY_NPC_GMAECIRCLE_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"에엥? 뭐라고? 불꽃이 안 나왔다고? 그럴 리가 없는데? 잘 못 본 거 아이가?","JPN":"ええ？　何やて？　炎が出なかった？　そんなはずないんやけどな？　見間違いじゃあらへん？","ENG":"Huh?! What’s that now? No fire? Can’t be! Ya must have missed it!","TWN":"啥？你說啥？你說沒看到火花？怎麼可能？是不是你眼花唄？"},"stage":{"bg":"AIRDOME","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"헤헷, 알았다! 내 다시 함 해볼게!","JPN":"へへっ、わかったわ！　もっかいやってみるわ！","ENG":"Heh, alrighty! Let me demonstrate for you folks again!","TWN":"嘿嘿，那好唄！我再施展一次唄！"},"stage":{"bg":"AIRDOME","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MILITARY_NPC_GMAECIRCLE_B","text":{"KOREA":"아, 알겠어! 알겠다고!","JPN":"わ、わかった！　わかったから！","ENG":"O-okay! Fine! We get it!","TWN":"有…有啦！我有看到！"},"stage":{"bg":"AIRDOME","slots":{"L":{"char_id":"MILITARY_NPC_GMAECIRCLE_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MILITARY_NPC_GMAECIRCLE_C","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MILITARY_NPC_GMAECIRCLE_B","text":{"KOREA":"이번에는 분명히 나오는 거 봤어! 부, 불꽃!","JPN":"今度は確かに出るの見えたよ！　ほ、炎！","ENG":"I definitely saw you flame this time! F-fwoosh!","TWN":"這次真的看到了啦！有…有火花！"},"stage":{"bg":"AIRDOME","slots":{"L":{"char_id":"MILITARY_NPC_GMAECIRCLE_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MILITARY_NPC_GMAECIRCLE_C","face":"UNIT_IDLE"}}}}]`);export{e as default};